  // ===== OFF-META & FLEX PICKS =====
  akshan: {"diff":"TRICKY","tone":"#ff8b3d","tldr":"Weather the poke — burst with E-Q and clone out before Heroic Swing answers.","breakdown":"Akshan plays around Heroic Swing. E in on the Heroic Swing cooldown, Q-shred armor, W-clone his counter, and the double-knockup R ends all-ins. Doran’s Shield blunts the poke war.","dos":["E-Q when Heroic Swing is down","W-decoy his answer","R the committed all-in"],"donts":["Burn the W clone early","Trade into his Heroic Swing","Engage without E attack speed"],"key":{"slot":"E","name":"Heroic Swing","cd":"14s","note":"His dash + camera swing escape. Engage when it's down.","winT":"SWING DOWN","winS":"E-Q shred, W out, R knockup."},"win":"Burst with E-Q and clone out before Heroic Swing answers."},
  cassiopeia: {"diff":"HARD","tone":"#ff5d6c","tldr":"He kites you out — survive, then burst with E-Q and clone out before Miasma answers.","breakdown":"Cassiopeia plays around Miasma. E in on the Miasma cooldown, Q-shred armor, W-clone his counter, and the double-knockup R ends all-ins. Take Mercs / MR shard — his damage is magic. Doran’s Shield blunts the poke war.","dos":["E-Q when Miasma is down","W-decoy his answer","R the committed all-in"],"donts":["Burn the W clone early","Trade into his Miasma","Engage without E attack speed"],"key":{"slot":"W","name":"Miasma","cd":"12s","note":"Grounds you — dashes and movement abilities are disabled inside it.","winT":"MIASMA DOWN","winS":"E-Q shred, W out, R knockup."},"win":"Burst with E-Q and clone out before Miasma answers."},
